import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if len(unvisited_customers) == 0:
        return None

    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])

    proximity_scores = []
    for customer in unvisited_customers:
        truck_proximities = np.array([distance(truck_pos, customer) for truck_pos in all_truck_pos])
        proximity_scores.append(np.sum(np.exp(-truck_proximities)))  # Using exponential decay to score proximity influence

    # Adjusted scoring function considering proximity influence more heavily
    beta = 0.5  # Influence from other trucks' proximity
    combined_scores = distances + beta * np.array(proximity_scores)

    best_node = np.argmin(combined_scores)

    return best_node
